     1→package org.schabi.newpipe.extractor.services.youtube;
     2→
     3→import org.schabi.newpipe.extractor.exceptions.ParsingException;
     4→import org.schabi.newpipe.extractor.utils.JavaScript;
     5→
     6→import javax.annotation.Nonnull;
     7→import javax.annotation.Nullable;
     8→import java.util.HashMap;
     9→import java.util.Map;
    10→import java.util.Objects;
    11→
    12→/**
    13→ * Manage the extraction and the usage of YouTube's player JavaScript needed data in the YouTube
    14→ * service.
    15→ *
    16→ * <p>
    17→ * YouTube restrict streaming their media in multiple ways by requiring their HTML5 clients to use
    18→ * a signature timestamp, and on streaming URLs a signature deobfuscation function for some
    19→ * contents and a throttling parameter deobfuscation one for all contents.
    20→ * </p>
    21→ *
    22→ * <p>
    23→ * This class provides access to methods which allows to get base JavaScript player's signature
    24→ * timestamp and to deobfuscate streaming URLs' signature and/or throttling parameter of HTML5
    25→ * clients.
    26→ * </p>
    27→ */
    28→public final class YoutubeJavaScriptPlayerManager {
    29→
    30→    @Nonnull
    31→    private static final Map<String, String> CACHED_THROTTLING_PARAMETERS = new HashMap<>();
    32→
    33→    private static String cachedJavaScriptPlayerCode;
    34→
    35→    @Nullable
    36→    private static Integer cachedSignatureTimestamp;
    37→    @Nullable
    38→    private static String cachedSignatureDeobfuscationFunction;
    39→    @Nullable
    40→    private static String cachedThrottlingDeobfuscationFunctionName;
    41→    @Nullable
    42→    private static String cachedThrottlingDeobfuscationFunction;
    43→
    44→    @Nullable
    45→    private static ParsingException throttlingDeobfFuncExtractionEx;
    46→    @Nullable
    47→    private static ParsingException sigDeobFuncExtractionEx;
    48→    @Nullable
    49→    private static ParsingException sigTimestampExtractionEx;
    50→
    51→    private YoutubeJavaScriptPlayerManager() {
    52→    }
    53→
    54→    /**
    55→     * Get the signature timestamp of the base JavaScript player file.
    56→     *
    57→     * <p>
    58→     * A valid signature timestamp sent in the payload of player InnerTube requests is required to
    59→     * get valid stream URLs on HTML5 clients for videos which have obfuscated signatures.
    60→     * </p>
    61→     *
    62→     * <p>
    63→     * The base JavaScript player file will fetched if it is not already done.
    64→     * </p>
    65→     *
    66→     * <p>
    67→     * The result of the extraction is cached until {@link #clearAllCaches()} is called, making
    68→     * subsequent calls faster.
    69→     * </p>
    70→     *
    71→     * @param videoId the video ID used to get the JavaScript base player file (an empty one can be
    72→     *                passed, even it is not recommend in order to spoof better official YouTube
    73→     *                clients)
    74→     * @return the signature timestamp of the base JavaScript player file
    75→     * @throws ParsingException if the extraction of the base JavaScript player file or the
    76→     * signature timestamp failed
    77→     */
    78→    @Nonnull
    79→    public static Integer getSignatureTimestamp(@Nonnull final String videoId)
    80→            throws ParsingException {
    81→        // Return the cached result if it is present
    82→        if (cachedSignatureTimestamp != null) {
    83→            return cachedSignatureTimestamp;
    84→        }
    85→
    86→        // If the signature timestamp has been not extracted on a previous call, this mean that we
    87→        // will fail to extract it on next calls too if the player code has been not changed
    88→        // Throw again the corresponding stored exception in this case to improve performance
    89→        if (sigTimestampExtractionEx != null) {
    90→            throw sigTimestampExtractionEx;
    91→        }
    92→
    93→        extractJavaScriptCodeIfNeeded(videoId);
    94→
    95→        try {
    96→            cachedSignatureTimestamp = Integer.valueOf(
    97→                    YoutubeSignatureUtils.getSignatureTimestamp(cachedJavaScriptPlayerCode));
    98→        } catch (final ParsingException e) {
    99→            // Store the exception for future calls of this method, in order to improve performance
   100→            sigTimestampExtractionEx = e;
   101→            throw e;
   102→        } catch (final NumberFormatException e) {
   103→            sigTimestampExtractionEx =
   104→                    new ParsingException("Could not convert signature timestamp to a number", e);
   105→        } catch (final Exception e) {
   106→            sigTimestampExtractionEx = new ParsingException("Could not get signature timestamp", e);
   107→            throw e;
   108→        }
   109→
   110→        return cachedSignatureTimestamp;
   111→    }
   112→
   113→    /**
   114→     * Deobfuscate a signature of a streaming URL using its corresponding JavaScript base player's
   115→     * function.
   116→     *
   117→     * <p>
   118→     * Obfuscated signatures are only present on streaming URLs of some videos with HTML5 clients.
   119→     * </p>
   120→     *
   121→     * @param videoId             the video ID used to get the JavaScript base player file (an
   122→     *                            empty one can be passed, even it is not recommend in order to
   123→     *                            spoof better official YouTube clients)
   124→     * @param obfuscatedSignature the obfuscated signature of a streaming URL
   125→     * @return the deobfuscated signature
   126→     * @throws ParsingException if the extraction of the base JavaScript player file or the
   127→     * signature deobfuscation function failed
   128→     */
   129→    @Nonnull
   130→    public static String deobfuscateSignature(@Nonnull final String videoId,
   131→                                              @Nonnull final String obfuscatedSignature)
   132→            throws ParsingException {
   133→        // If the signature deobfuscation function has been not extracted on a previous call, this
   134→        // mean that we will fail to extract it on next calls too if the player code has been not
   135→        // changed
   136→        // Throw again the corresponding stored exception in this case to improve performance
   137→        if (sigDeobFuncExtractionEx != null) {
   138→            throw sigDeobFuncExtractionEx;
   139→        }
   140→
   141→        extractJavaScriptCodeIfNeeded(videoId);
   142→
   143→        if (cachedSignatureDeobfuscationFunction == null) {
   144→            try {
   145→                cachedSignatureDeobfuscationFunction = YoutubeSignatureUtils.getDeobfuscationCode(
   146→                        cachedJavaScriptPlayerCode);
   147→            } catch (final ParsingException e) {
   148→                // Store the exception for future calls of this method, in order to improve
   149→                // performance
   150→                sigDeobFuncExtractionEx = e;
   151→                throw e;
   152→            } catch (final Exception e) {
   153→                sigDeobFuncExtractionEx = new ParsingException(
   154→                        "Could not get signature parameter deobfuscation JavaScript function", e);
   155→                throw e;
   156→            }
   157→        }
   158→
   159→        try {
   160→            // Return an empty parameter in the case the function returns null
   161→            return Objects.requireNonNullElse(
   162→                    JavaScript.run(cachedSignatureDeobfuscationFunction,
   163→                            YoutubeSignatureUtils.DEOBFUSCATION_FUNCTION_NAME,
   164→                            obfuscatedSignature), "");
   165→        } catch (final Exception e) {
   166→            // This shouldn't happen as the function validity is checked when it is extracted
   167→            throw new ParsingException(
   168→                    "Could not run signature parameter deobfuscation JavaScript function", e);
   169→        }
   170→    }
   171→
   172→    /**
   173→     * Return a streaming URL with the throttling parameter of a given one deobfuscated, if it is
   174→     * present, using its corresponding JavaScript base player's function.
   175→     *
   176→     * <p>
   177→     * The throttling parameter is present on all streaming URLs of HTML5 clients.
   178→     * </p>
   179→     *
   180→     * <p>
   181→     * If it is not given or deobfuscated, speeds will be throttled to a very slow speed (around 50
   182→     * KB/s) and some streaming URLs could even lead to invalid HTTP responses such a 403 one.
   183→     * </p>
   184→     *
   185→     * <p>
   186→     * As throttling parameters can be common between multiple streaming URLs of the same player
   187→     * response, deobfuscated parameters are cached with their obfuscated variant, in order to
   188→     * improve performance with multiple calls of this method having the same obfuscated throttling
   189→     * parameter.
   190→     * </p>
   191→     *
   192→     * <p>
   193→     * The cache's size can be get using {@link #getThrottlingParametersCacheSize()} and the cache
   194→     * can be cleared using {@link #clearThrottlingParametersCache()} or {@link #clearAllCaches()}.
   195→     * </p>
   196→     *
   197→     * @param videoId      the video ID used to get the JavaScript base player file (an empty one
   198→     *                     can be passed, even it is not recommend in order to spoof better
   199→     *                     official YouTube clients)
   200→     * @param streamingUrl a streaming URL
   201→     * @return the original streaming URL if it has no throttling parameter or a URL with a
   202→     * deobfuscated throttling parameter
   203→     * @throws ParsingException if the extraction of the base JavaScript player file or the
   204→     * throttling parameter deobfuscation function failed
   205→     */
   206→    @Nonnull
   207→    public static String getUrlWithThrottlingParameterDeobfuscated(
   208→            @Nonnull final String videoId,
   209→            @Nonnull final String streamingUrl) throws ParsingException {
   210→        final String obfuscatedThrottlingParameter =
   211→                YoutubeThrottlingParameterUtils.getThrottlingParameterFromStreamingUrl(
   212→                        streamingUrl);
   213→        // If the throttling parameter is not present, return the original streaming URL
   214→        if (obfuscatedThrottlingParameter == null) {
   215→            return streamingUrl;
   216→        }
   217→
   218→        // Do not use the containsKey method of the Map interface in order to avoid a double
   219→        // element search, and so to improve performance
   220→        final String cacheResult = CACHED_THROTTLING_PARAMETERS.get(
   221→                obfuscatedThrottlingParameter);
   222→        if (cacheResult != null) {
   223→            // If the throttling parameter function has been already ran on the throttling parameter
   224→            // of the current streaming URL, replace directly the obfuscated throttling parameter
   225→            // with the cached result in the streaming URL
   226→            return streamingUrl.replace(obfuscatedThrottlingParameter, cacheResult);
   227→        }
   228→
   229→        extractJavaScriptCodeIfNeeded(videoId);
   230→
   231→        // If the throttling parameter deobfuscation function has been not extracted on a previous
   232→        // call, this mean that we will fail to extract it on next calls too if the player code has
   233→        // been not changed
   234→        // Throw again the corresponding stored exception in this case to improve performance
   235→        if (throttlingDeobfFuncExtractionEx != null) {
   236→            throw throttlingDeobfFuncExtractionEx;
   237→        }
   238→
   239→        if (cachedThrottlingDeobfuscationFunction == null) {
   240→            try {
   241→                cachedThrottlingDeobfuscationFunctionName =
   242→                        YoutubeThrottlingParameterUtils.getDeobfuscationFunctionName(
   243→                                cachedJavaScriptPlayerCode);
   244→
   245→                cachedThrottlingDeobfuscationFunction =
   246→                        YoutubeThrottlingParameterUtils.getDeobfuscationFunction(
   247→                                cachedJavaScriptPlayerCode,
   248→                                cachedThrottlingDeobfuscationFunctionName);
   249→            } catch (final ParsingException e) {
   250→                // Store the exception for future calls of this method, in order to improve
   251→                // performance
   252→                throttlingDeobfFuncExtractionEx = e;
   253→                throw e;
   254→            } catch (final Exception e) {
   255→                throttlingDeobfFuncExtractionEx = new ParsingException(
   256→                        "Could not get throttling parameter deobfuscation JavaScript function", e);
   257→                throw e;
   258→            }
   259→        }
   260→
   261→        try {
   262→            final String deobfuscatedThrottlingParameter = JavaScript.run(
   263→                    cachedThrottlingDeobfuscationFunction,
   264→                    cachedThrottlingDeobfuscationFunctionName,
   265→                    obfuscatedThrottlingParameter);
   266→
   267→            CACHED_THROTTLING_PARAMETERS.put(
   268→                    obfuscatedThrottlingParameter, deobfuscatedThrottlingParameter);
   269→
   270→            return streamingUrl.replace(
   271→                    obfuscatedThrottlingParameter, deobfuscatedThrottlingParameter);
   272→        } catch (final Exception e) {
   273→            // This shouldn't happen as the function validity is checked when it is extracted
   274→            throw new ParsingException(
   275→                    "Could not run throttling parameter deobfuscation JavaScript function", e);
   276→        }
   277→    }
   278→
   279→    /**
   280→     * Get the current cache size of throttling parameters.
   281→     *
   282→     * @return the current cache size of throttling parameters
   283→     */
   284→    public static int getThrottlingParametersCacheSize() {
   285→        return CACHED_THROTTLING_PARAMETERS.size();
   286→    }
   287→
   288→    /**
   289→     * Clear all caches.
   290→     *
   291→     * <p>
   292→     * This method will clear all cached JavaScript code and throttling parameters.
   293→     * </p>
   294→     *
   295→     * <p>
   296→     * The next time {@link #getSignatureTimestamp(String)},
   297→     * {@link #deobfuscateSignature(String, String)} or
   298→     * {@link #getUrlWithThrottlingParameterDeobfuscated(String, String)} is called, the JavaScript
   299→     * code will be fetched again and the corresponding extraction methods will be ran.
   300→     * </p>
   301→     */
   302→    public static void clearAllCaches() {
   303→        cachedJavaScriptPlayerCode = null;
   304→        cachedSignatureDeobfuscationFunction = null;
   305→        cachedThrottlingDeobfuscationFunctionName = null;
   306→        cachedThrottlingDeobfuscationFunction = null;
   307→        cachedSignatureTimestamp = null;
   308→        clearThrottlingParametersCache();
   309→
   310→        // Clear cached extraction exceptions, if applicable
   311→        throttlingDeobfFuncExtractionEx = null;
   312→        sigDeobFuncExtractionEx = null;
   313→        sigTimestampExtractionEx = null;
   314→    }
   315→
   316→    /**
   317→     * Clear all cached throttling parameters.
   318→     *
   319→     * <p>
   320→     * The throttling parameter deobfuscation function will be ran again on these parameters if
   321→     * streaming URLs containing them are passed in the future.
   322→     * </p>
   323→     *
   324→     * <p>
   325→     * This method doesn't clear the cached throttling parameter deobfuscation function, this can
   326→     * be done using {@link #clearAllCaches()}.
   327→     * </p>
   328→     */
   329→    public static void clearThrottlingParametersCache() {
   330→        CACHED_THROTTLING_PARAMETERS.clear();
   331→    }
   332→
   333→    /**
   334→     * Extract the JavaScript code if it isn't already cached.
   335→     *
   336→     * @param videoId the video ID used to get the JavaScript base player file (an empty one can be
   337→     *                passed, even it is not recommend in order to spoof better official YouTube
   338→     *                clients)
   339→     * @throws ParsingException if the extraction of the base JavaScript player file failed
