     1→package org.schabi.newpipe.extractor.services.youtube;
     2→
     3→import org.jsoup.Jsoup;
     4→import org.jsoup.nodes.Document;
     5→import org.jsoup.nodes.Element;
     6→import org.jsoup.select.Elements;
     7→import org.schabi.newpipe.extractor.NewPipe;
     8→import org.schabi.newpipe.extractor.exceptions.ParsingException;
     9→import org.schabi.newpipe.extractor.localization.Localization;
    10→import org.schabi.newpipe.extractor.utils.Parser;
    11→
    12→import javax.annotation.Nonnull;
    13→import java.net.MalformedURLException;
    14→import java.net.URL;
    15→import java.util.regex.Pattern;
    16→
    17→/**
    18→ * The extractor of YouTube's base JavaScript player file.
    19→ *
    20→ * <p>
    21→ * This class handles fetching of this base JavaScript player file in order to allow other classes
    22→ * to extract the needed data.
    23→ * </p>
    24→ *
    25→ * <p>
    26→ * It will try to get the player URL from YouTube's IFrame resource first, and from a YouTube embed
    27→ * watch page as a fallback.
    28→ * </p>
    29→ */
    30→final class YoutubeJavaScriptExtractor {
    31→
    32→    private static final String HTTPS = "https:";
    33→    private static final String BASE_JS_PLAYER_URL_FORMAT =
    34→            "https://www.youtube.com/s/player/%s/player_ias.vflset/en_GB/base.js";
    35→    private static final Pattern IFRAME_RES_JS_BASE_PLAYER_HASH_PATTERN = Pattern.compile(
    36→            "player\\\\/([a-z0-9]{8})\\\\/");
    37→    private static final Pattern EMBEDDED_WATCH_PAGE_JS_BASE_PLAYER_URL_PATTERN = Pattern.compile(
    38→            "\"jsUrl\":\"(/s/player/[A-Za-z0-9]+/player_ias\\.vflset/[A-Za-z_-]+/base\\.js)\"");
    39→
    40→    private YoutubeJavaScriptExtractor() {
    41→    }
    42→
    43→    /**
    44→     * Extracts the JavaScript base player file.
    45→     *
    46→     * @param videoId the video ID used to get the JavaScript base player file (an empty one can be
    47→     *                passed, even it is not recommend in order to spoof better official YouTube
    48→     *                clients)
    49→     * @return the whole JavaScript base player file as a string
    50→     * @throws ParsingException if the extraction of the file failed
    51→     */
    52→    @Nonnull
    53→    static String extractJavaScriptPlayerCode(@Nonnull final String videoId)
    54→            throws ParsingException {
    55→        String url;
    56→        try {
    57→            url = YoutubeJavaScriptExtractor.extractJavaScriptUrlWithIframeResource();
    58→            final String playerJsUrl = YoutubeJavaScriptExtractor.cleanJavaScriptUrl(url);
    59→
    60→            // Assert that the URL we extracted and built is valid
    61→            new URL(playerJsUrl);
    62→
    63→            return YoutubeJavaScriptExtractor.downloadJavaScriptCode(playerJsUrl);
    64→        } catch (final Exception e) {
    65→            url = YoutubeJavaScriptExtractor.extractJavaScriptUrlWithEmbedWatchPage(videoId);
    66→            final String playerJsUrl = YoutubeJavaScriptExtractor.cleanJavaScriptUrl(url);
    67→
    68→            try {
    69→                // Assert that the URL we extracted and built is valid
    70→                new URL(playerJsUrl);
    71→            } catch (final MalformedURLException exception) {
    72→                throw new ParsingException(
    73→                        "The extracted and built JavaScript URL is invalid", exception);
    74→            }
    75→
    76→            return YoutubeJavaScriptExtractor.downloadJavaScriptCode(playerJsUrl);
    77→        }
    78→    }
    79→
    80→    @Nonnull
    81→    static String extractJavaScriptUrlWithIframeResource() throws ParsingException {
    82→        final String iframeUrl;
    83→        final String iframeContent;
    84→        try {
    85→            iframeUrl = "https://www.youtube.com/iframe_api";
    86→            iframeContent = NewPipe.getDownloader()
    87→                    .get(iframeUrl, Localization.DEFAULT)
    88→                    .responseBody();
    89→        } catch (final Exception e) {
    90→            throw new ParsingException("Could not fetch IFrame resource", e);
    91→        }
    92→
    93→        try {
    94→            final String hash = Parser.matchGroup1(
    95→                    IFRAME_RES_JS_BASE_PLAYER_HASH_PATTERN, iframeContent);
    96→            return String.format(BASE_JS_PLAYER_URL_FORMAT, hash);
    97→        } catch (final Parser.RegexException e) {
    98→            throw new ParsingException(
    99→                    "IFrame resource didn't provide JavaScript base player's hash", e);
   100→        }
   101→    }
   102→
   103→    @Nonnull
   104→    static String extractJavaScriptUrlWithEmbedWatchPage(@Nonnull final String videoId)
