import org.schabi.newpipe.extractor.services.youtube.YoutubeThrottlingParameterUtils;
import java.io.*;
import java.util.regex.*;

public class test_throttling_debug {
    public static void main(String[] args) {
        try {
            // Initialize
            final String RESOURCE_PATH = DownloaderFactory.RESOURCE_PATH + "services/youtube/extractor/jsExtractor/playerCode";
            NewPipe.init(DownloaderFactory.getDownloader(RESOURCE_PATH));

            // Extract JavaScript code
            String jsCode = YoutubeJavaScriptExtractor.extractJavaScriptPlayerCode("jE1USQrs1rw");

            // Search for patterns related to throttling parameter
            String[] searchPatterns = new String[]{
                ".{0,150}=\"nn\"\\[.{0,150}",
                ".{0,150}\\.get\\(\"n\"\\).{0,150}",
                ".{0,150}String\\.fromCharCode\\(110\\).{0,150}"
            };

            System.out.println("Player code length: " + jsCode.length());
            System.out.println("\nSearching for throttling-related patterns:");

            for (int i = 0; i < searchPatterns.length; i++) {
                System.out.println("\n=== Pattern " + (i+1) + ": " + searchPatterns[i] + " ===");
                Pattern pattern = Pattern.compile(searchPatterns[i]);
                Matcher matcher = pattern.matcher(jsCode);
                int count = 0;
                while (matcher.find() && count < 3) {
                    String match = matcher.group();
                    System.out.println("Match " + (++count) + ":");
                    System.out.println(match);
                    System.out.println("---");
                }
                if (count == 0) {
                    System.out.println("No matches found");
                }
            }

        } catch (Exception e) {
            e.printStackTrace();
        }
    }
}

