import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.schabi.newpipe.downloader.DownloaderFactory;
import org.schabi.newpipe.extractor.NewPipe;

import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class DebugThrottlingPattern3 {
    private static final String RESOURCE_PATH =
            DownloaderFactory.RESOURCE_PATH + "services/youtube/extractor/jsExtractor/playerCode";

    @BeforeEach
    void setup() {
        YoutubeTestsUtils.ensureStateless();
        NewPipe.init(DownloaderFactory.getDownloader(RESOURCE_PATH));
    }

    @Test
    public void debugPatterns() throws Exception {
        // Extract JavaScript code
        String jsCode = YoutubeJavaScriptExtractor.extractJavaScriptPlayerCode("jE1USQrs1rw");

        System.out.println("Player code length: " + jsCode.length());

        // Look for the function that calls ".get("n")" and uses H_ constructor
        // This is the throttling function: Ioj=function(S){try{var W=(new g.H_(S,!0)).get("n");...
        System.out.println("\n=== Looking for throttling function name ===");
        Pattern pattern = Pattern.compile("([a-zA-Z0-9$_]+)\\=function\\([a-zA-Z0-9$_]+\\)\\{try\\{var [a-zA-Z0-9$_]+\\=\\(new g\\.[a-zA-Z0-9$_]+\\([a-zA-Z0-9$_]+[,!][^)]+\\)\\)\\.get\\(\"n\"\\)");
        Matcher matcher = pattern.matcher(jsCode);
        if (matcher.find()) {
            System.out.println("Function name: " + matcher.group(1));
            System.out.println("Full match: " + matcher.group());
        }

        // Now let's look for QP function
        System.out.println("\n=== Looking for QP function ===");
        pattern = Pattern.compile("QP\\s*=\\s*function[^}]{0,1000}\\}");
        matcher = pattern.matcher(jsCode);
        int count = 0;
        while (matcher.find() && count < 3) {
            String match = matcher.group();
            System.out.println("Match " + (++count) + ":");
            System.out.println(match.substring(0, Math.min(500, match.length())));
            System.out.println("---");
        }

        // Look for the actual Ioj function definition to understand its structure
        System.out.println("\n=== Looking for full Ioj function ===");
