import static org.junit.jupiter.api.Assertions.*;

public class TestFunctionNameExtraction {
    private static final String RESOURCE_PATH =
            DownloaderFactory.RESOURCE_PATH + "services/youtube/extractor/jsExtractor/playerCode";

    @BeforeEach
    void setup() {
        YoutubeTestsUtils.ensureStateless();
        NewPipe.init(DownloaderFactory.getDownloader(RESOURCE_PATH));
    }

    @Test
    public void testGetDeobfuscationFunctionName() throws Exception {
        // Extract JavaScript code
        String jsCode = YoutubeJavaScriptExtractor.extractJavaScriptPlayerCode("jE1USQrs1rw");

        // Try to get the function name
        String functionName = YoutubeThrottlingParameterUtils.getDeobfuscationFunctionName(jsCode);

        System.out.println("Function name found: " + functionName);
        assertNotNull(functionName);
        assertFalse(functionName.isEmpty());
        assertEquals("Ioj", functionName);
    }

    @Test
    public void testGetDeobfuscationFunction() throws Exception {
        // Extract JavaScript code
        String jsCode = YoutubeJavaScriptExtractor.extractJavaScriptPlayerCode("jE1USQrs1rw");

        // Try to get the function name
        String functionName = YoutubeThrottlingParameterUtils.getDeobfuscationFunctionName(jsCode);

        System.out.println("Function name: " + functionName);

        // Try to get the function code
        String function = YoutubeThrottlingParameterUtils.getDeobfuscationFunction(jsCode, functionName);

        System.out.println("Function code length: " + function.length());
        System.out.println("Function code:\n" + function.substring(0, Math.min(500, function.length())));

        assertNotNull(function);
        assertFalse(function.isEmpty());
    }
}

