import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class DebugDependencies {
    private static final String RESOURCE_PATH =
            DownloaderFactory.RESOURCE_PATH + "services/youtube/extractor/jsExtractor/playerCode";

    @BeforeEach
    void setup() {
        YoutubeTestsUtils.ensureStateless();
        NewPipe.init(DownloaderFactory.getDownloader(RESOURCE_PATH));
    }

    @Test
    public void debugDependencies() throws Exception {
        // Extract JavaScript code
        String jsCode = YoutubeJavaScriptExtractor.extractJavaScriptPlayerCode("jE1USQrs1rw");

        System.out.println("Player code length: " + jsCode.length());

        // Look for g.H_ definition
        System.out.println("\n=== Looking for g.H_ definition ===");
        Pattern pattern = Pattern.compile("g\\.H_\\s*=\\s*function[^;]+;");
        Matcher matcher = pattern.matcher(jsCode);
        if (matcher.find()) {
            System.out.println("g.H_ definition:");
            System.out.println(matcher.group());
        }

        // Look for QP function that g.H_ calls
        System.out.println("\n=== Looking for QP function (first occurrence) ===");
        pattern = Pattern.compile("(QP|g\\.QP)\\s*=\\s*function\\([^)]*\\)\\{[^}]*z\\[7][^}]*\\}");
        matcher = pattern.matcher(jsCode);
