        System.out.println("\n=== Looking for g.Ue definition ===");
        pattern = Pattern.compile("g\\.Ue\\s*=\\s*function[^;]+;");
        matcher = pattern.matcher(jsCode);
        if (matcher.find()) {
            System.out.println("g.Ue definition:");
            System.out.println(matcher.group());
