        // Look for the "z" array/object that contains string indices
        System.out.println("\n=== Looking for z definition ===");
        pattern = Pattern.compile("(var\\s+z\\s*=|z\\s*=)[^;]+;");
        matcher = pattern.matcher(jsCode);
        count = 0;
        while (matcher.find() && count < 3) {
            String match = matcher.group();
            System.out.println("Match " + (++count) + ":");
            System.out.println(match.substring(0, Math.min(200, match.length())));
            System.out.println("---");
        }
    }
