import org.junit:jupiter.api.Test;
import org.schabi.newpipe.downloader.DownloaderFactory;
import org.schabi.newpipe.extractor.NewPipe;

import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class DebugActualThrottlingFunction {
    private static final String RESOURCE_PATH =
            DownloaderFactory.RESOURCE_PATH + "services/youtube/extractor/jsExtractor/playerCode";

    @BeforeEach
    void setup() {
        YoutubeTestsUtils.ensureStateless();
        NewPipe.init(DownloaderFactory.getDownloader(RESOURCE_PATH));
    }

    @Test
    public void debugActualFunction() throws Exception {
        // Extract JavaScript code
        String jsCode = YoutubeJavaScriptExtractor.extractJavaScriptPlayerCode("jE1USQrs1rw");

        System.out.println("Player code length: " + jsCode.length());

        // The Ioj function calls (new g.H_(S,!0)).get("n")
        // g.H_ is defined as: g.H_=function(S,W){return QP[z[7]](this,6,S,W)};
        // So g.H_ calls QP[z[7]]
        // We need to find what QP[z[7]] is

        // First, let's find where z[7] is defined
        System.out.println("\n=== Looking for array z definition ===");
        // Look for z as an array
        Pattern pattern = Pattern.compile("var z\\s*=\\s*\\[[^\\]]{0,1000}\\]");
        Matcher matcher = pattern.matcher(jsCode);
        if (matcher.find()) {
            String match = matcher.group();
            System.out.println("z array (first 500 chars):");
            System.out.println(match.substring(0, Math.min(500, match.length())));

            // Parse to get z[7]
            String[] elements = match.substring(match.indexOf('[') + 1, match.lastIndexOf(']')).split(",");
            if (elements.length > 7) {
                System.out.println("\nz[7] = " + elements[7].trim());
            }
        }

        // Look for QP as an array
        System.out.println("\n=== Looking for QP array definition ===");
        pattern = Pattern.compile("(var\\s+)?QP\\s*=\\s*\\[[^\\]]{0,500}\\]");
        matcher = pattern.matcher(jsCode);
        if (matcher.find()) {
            System.out.println("QP array:");
            System.out.println(matcher.group());
        }

        // Look for QP as an object with methods
        System.out.println("\n=== Looking for QP object definition ===");
        pattern = Pattern.compile("QP\\s*=\\s*\\{[^}]{0,500}\\}");
        matcher = pattern.matcher(jsCode);
        int count = 0;
        while (matcher.find() && count < 3) {
            System.out.println("Match " + (++count) + ":");
            System.out.println(matcher.group());
            System.out.println("---");
        }
    }
}

