/**
 * Extract helper object dependencies from the function.
 *
 * <p>For functions that use objects like "g.H_" or "g.Ue", we need to extract those
 * object properties and include them in the executable code.</p>
 *
 * @param javaScriptPlayerCode the complete JavaScript base player code
 * @param function the throttling function that may have dependencies
 * @return the helper object code that needs to be prepended to the function
 * @throws ParsingException if the helper object extraction fails
 */
@Nonnull
private static String extractHelperObject(@Nonnull final String javaScriptPlayerCode,
                                          @Nonnull final String function)
        throws ParsingException {
    // Create a mock "g" object with the necessary methods
    // We need to extract: g.H_, g.Ue, and potentially others
    final StringBuilder helperObject = new StringBuilder("var g={};");

    // Extract g.H_ if used in the function
    if (function.contains("g.H_")) {
        try {
            final Pattern gH_Pattern = Pattern.compile("g\\.H_\\s*=\\s*function[^;]+;");
            final String gH_Def = Parser.matchGroup(gH_Pattern, javaScriptPlayerCode, 0);
            helperObject.append(gH_Def);

            // g.H_ might call other functions, we need to extract those too
            // For now, let's try a different approach - extract the constructor it calls
            extractHelperDependencies(javaScriptPlayerCode, gH_Def, helperObject);
        } catch (final Exception e) {
            // Continue without g.H_ - might still work
        }
    }

    // Extract g.Ue if used in the function (error handler)
    if (function.contains("g.Ue")) {
