            try {
                final Pattern gH_Pattern = Pattern.compile("g\\.H_\\s*=\\s*function[^;]+;");
                final String gH_Def = Parser.matchGroup(gH_Pattern, javaScriptPlayerCode, 0);
                helperObject.append(gH_Def);

                // g.H_ might call other functions, we need to extract those too
                // For now, let's try a different approach - extract the constructor it calls
                extractHelperDependencies(javaScriptPlayerCode, gH_Def, helperObject);
            } catch (final Exception e) {
                // Continue without g.H_ - might still work
            }
        }

        // Extract g.Ue if used in the function (error handler)
        if (function.contains("g.Ue")) {
            try {
                final Pattern gUePattern = Pattern.compile("g\\.Ue\\s*=\\s*function[^;]+;");
                final String gUeDef = Parser.matchGroup(gUePattern, javaScriptPlayerCode, 0);
                helperObject.append(gUeDef);
            } catch (final Exception e) {
                // g.Ue is just for error handling, provide a noop
                helperObject.append("g.Ue=function(a){};");
            }
        }

        return helperObject.toString();
    }

