                EARLY_RETURN_REGEX + firstArgName + ";",
                Pattern.DOTALL);
        final Matcher earlyReturnCodeMatcher = earlyReturnPattern.matcher(function);
        return earlyReturnCodeMatcher.replaceFirst(";");
    }
}

