        try {
            function = parseFunctionWithLexer(javaScriptPlayerCode, functionName);
        } catch (final Exception e) {
            function = parseFunctionWithRegex(javaScriptPlayerCode, functionName);
        }
        function = fixupFunction(function);

        // Check if the function uses the "g" object (e.g., g.H_, g.Ue, etc.)
        // If so, we need to extract the relevant parts of the g object
        if (function.contains("new g.")) {
            // Extract helper object dependencies
            try {
                final String helperObject = extractHelperObject(javaScriptPlayerCode, function);
                function = helperObject + function;
