     * @return the helper object code that needs to be prepended to the function
     * @throws ParsingException if the helper object extraction fails
     */
    @Nonnull
    private static String extractHelperObject(@Nonnull final String javaScriptPlayerCode,
                                              @Nonnull final String function)
