package org.schabi.newpipe.extractor.services.youtube;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.schabi.newpipe.downloader.DownloaderFactory;
import org.schabi.newpipe.extractor.NewPipe;

import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class SearchForAlternativeFunction {
    private static final String RESOURCE_PATH =
            DownloaderFactory.RESOURCE_PATH + "services/youtube/extractor/jsExtractor/playerCode";

    @BeforeEach
    void setup() {
        YoutubeTestsUtils.ensureStateless();
        NewPipe.init(DownloaderFactory.getDownloader(RESOURCE_PATH));
    }

    @Test
    public void searchForAlternative() throws Exception {
        // Extract JavaScript code
        String jsCode = YoutubeJavaScriptExtractor.extractJavaScriptPlayerCode("jE1USQrs1rw");

        System.out.println("Player code length: " + jsCode.length());

        // Search for functions that look like they transform a string and return it
        // These might be the actual n-parameter transformation functions
        // Look for patterns like: functionName=function(a){<string manipulation>...return ...}

        System.out.println("\n=== Searching for functions with 'split' and 'join' (string manipulation) ===");
        Pattern pattern = Pattern.compile("([a-zA-Z0-9$_]{2,})\\s*=\\s*function\\(([a-zA-Z0-9$_])\\)\\{[^}]*\\2\\.split\\([^}]*\\.join\\([^}]{0,300}\\}");
        Matcher matcher = pattern.matcher(jsCode);
        int count = 0;
        while (matcher.find() && count < 5) {
            System.out.println("Match " + (++count) + ":");
            System.out.println("Function name: " + matcher.group(1));
            System.out.println("Full match: " + matcher.group());
            System.out.println("---");
        }

        // Look for the constructor/class that g.H_ points to
        // g.H_=function(S,W){return QP[z[7]](this,6,S,W)};
        // We need to find what QP is
        System.out.println("\n=== Searching for QP definition ===");
        // QP might be defined as an array or object
        pattern = Pattern.compile("(var\\s+|\\b)QP\\s*=\\s*\\[");
        matcher = pattern.matcher(jsCode);
        if (matcher.find()) {
            int start = matcher.start();
            System.out.println("Found QP array at position: " + start);
            System.out.println("Context: " + jsCode.substring(Math.max(0, start - 50), Math.min(jsCode.length(), start + 500)));
        }
    }
}

