    final StringBuilder helperObject = new StringBuilder();

    // Create the g object
    helperObject.append("var g={};");

    // Extract g.H_ if used
    if (function.contains("g.H_")) {
        try {
            final Pattern ghPattern = Pattern.compile("g\\.H_\\s*=\\s*function[^;]+;");
            final String ghDef = Parser.matchGroup(ghPattern, javaScriptPlayerCode, 0);
            helperObject.append(ghDef);

            // g.H_ calls QP[z[7]], so we need to extract QP and z
            extractQPFunction(javaScriptPlayerCode, helperObject);
            extractZArray(javaScriptPlayerCode, helperObject);
        } catch (final Exception e) {
            // If we can't extract dependencies, provide a noop that prevents crashes
            helperObject.append("g.H_=function(S,W){this.get=function(p){");
            helperObject.append("if(p==='n'){var m=S.match(/[&?]n=([^&]+)/);return m?m[1]:null;}");
            helperObject.append("return null;};};");
        }
    }

    // g.Ue is just for error handling, provide a noop
    if (function.contains("g.Ue")) {
        helperObject.append("g.Ue=function(a){};");
    }

    return helperObject.toString();
}

private static void extractQPFunction(@Nonnull final String javaScriptPlayerCode,
                                      @Nonnull final StringBuilder helperObject) {
    try {
